head.script:
/**
 * 화 면 명 : 임대차[전대차] 계약기본정보
 * 메뉴경로 : 공통/총무업무/임대차관리/임대차[전대차] 계약관리
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/cm/bc/rentloan/zz_900_01_02b.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-11-19
 * 수정이력  :
 *    - 2025-11-19      정승혜    최초작성
 *    - 2025-12-23      정승혜    pub 경로 -> ui로 변경 / f_winOpen수정 / 자산 팝업 수정
 *    - 2025-12-24      정승혜    popTitleCh 적용
 *    - 2026-01-05      정승혜    기타수정
 *    - 2026-01-08      정승혜    우편번호수정
 *    - 2026-01-16      정승혜    getMemInfo 이동
 *    - 2026-01-19      정승혜    submitdone 조건수정
 * 메모 : 
 * 다른페이지들과 일치시키기 위하여 구조 조금 바꿈 / 명소소송현황 버튼 하나더 사용하지 않고 조건처리 / f_RentloanShapeCdChange 함수추가
 * 조회조건: 
 * A20251028001 /  "uppermostBizDomCd": "252",
 * C20160720001 /  "uppermostBizDomCd": "200", / 관리비납부일
 * 해야할 리스트 : 
 */

//hidden
scwin.hid_uppermostBizDomCd = "";
scwin.hid_rentloanEndDt = "";
scwin.hid_loanCtrtNm = "";
scwin.txt_fixedAsetNm = "";
scwin.ed_coCd = "";

scwin.sDate = $c.date.getServerDateTime("yyyyMMdd");

scwin.params = "";
scwin.rentloanNo = "";
scwin.rentloanSeq = "";
scwin.rentloanNoSeq = "";
scwin.rentloanKbn = "";
scwin.strBasSdId = "";
scwin.eqSelBizDom = "";
scwin.cfValue = "";
scwin.popYn = "";
scwin.iCfVal = "";

scwin.memJson = "";
scwin.regId = "";
scwin.sysAdminYn = "";
scwin.acctDeptCd = "";
scwin.acctDeptNm = "";
scwin.user = "";
scwin.coCd = "";

//////////////////////////////
scwin.uppermostBizDomCd = ""; //최상위사업영역
scwin.selBizDom = scwin.eqSelBizDom;
//////////////////////////////

scwin.vLoginCoCd = "";
if(scwin.coCd == null){scwin.vLoginCoCd = "";}else{scwin.vLoginCoCd = scwin.coCd};  // 소속 자회사

  //-------------------------------------------------------------------------
  // 화면로딩시
  //-------------------------------------------------------------------------
scwin.onpageload = function() {
    console.log("zz_900_01_02b_pgmId : "+$c.data.getParameter($p, "menuInfo").pgmId)

    if($c.data.getMemInfo() != null && $c.data.getMemInfo() != undefined ){
        scwin.memJson = $c.data.getMemInfo();
        scwin.regId = scwin.memJson.userId;
        scwin.sysAdminYn = scwin.memJson.sysAdminYn;
    }

    scwin.acctDeptCd = "";
    if(scwin.memJson.acctDeptCd == null){scwin.acctDeptCd = "";}else{scwin.acctDeptCd = scwin.memJson.acctDeptCd}

    scwin.acctDeptNm = "";
    if(scwin.memJson.acctDeptNm == null){scwin.acctDeptNm = "";}else{scwin.acctDeptNm = scwin.memJson.acctDeptNm}

    scwin.user = scwin.regId;
    scwin.coCd = scwin.memJson.coCd;

    if($c.data.getParameter() != null && $c.data.getParameter() != undefined ){
        scwin.params = $c.data.getParameter();
    }

    scwin.rentloanNo = scwin.params["rentloanNo"];
    scwin.rentloanSeq = scwin.params["rentloanSeq"];
    scwin.rentloanNoSeq = scwin.params["rentloanNo"] + scwin.params["rentloanSeq"];    
    if(scwin.params["mode"] == null){scwin.rentloanKbn = "";}else{scwin.rentloanKbn = scwin.params["mode"]} //NEW, CHG, REN, MOD, DEL, ''
    if(scwin.params["selBizDom"] == null){scwin.eqSelBizDom = "";}else{scwin.eqSelBizDom = scwin.params["selBizDom"]}
    if(scwin.eqSelBizDom == "000"){ scwin.eqSelBizDom = "252"; }
    if(scwin.params["cf"] == null){scwin.cfValue = "";}else{scwin.cfValue = scwin.params["cf"]}
    if(scwin.params["popYn"] == null){scwin.popYn = "";}else{scwin.popYn = scwin.params["popYn"]}
    scwin.iCfVal = parseInt(scwin.cfValue);

    switch (scwin.iCfVal) {
        case 1 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_01_01b.xml"; break;
        case 2 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_04_01b.xml"; break;
        case 3 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_03_01b.xml"; break;
        case 4 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_03_02b.xml"; break;
        case 5 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_03_04b.xml"; break;
        case 8 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_08_01b.xml"; break;
        case 9 : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_09_01b.xml"; break;
        default : scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_01_01b.xml"; break;
    }
};

scwin.onUdcCompleted = function() {    
    const codeOptions = [
    { grpCd : "ZZ920", compID : "gr_out2:goodsCd, lc_goodsCd" },
    { grpCd : "SD030", compID : "gr_out2:regAreaM2" },
    { grpCd : "ZZ910", compID : "lc_rentloanClsCd" },
    { grpCd : "ZZ911", compID : "lc_rentloanShapeCd" },
    { grpCd : "ZZ913", compID : "lc_usePurpsCd" },
    { grpCd : "ZZ912", compID : "lc_rentloanCond" },
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.ondataload = function() {
    //codeOptions load 이후에 실행됨 / ds_out2 매핑이 안되서 여기서 함수실행

    $c.gus.cfDisableObjects([ed_rentloanNo,pu_ctrt]);
    scwin.f_HeaderCreate();

    //로그인한 사번으로 최상위사업영역을 가져오는 데이타셋 실행
    scwin.f_uppermostBizdom();

    if(scwin.rentloanNo != undefined && scwin.rentloanSeq != undefined){        
        scwin.f_Retrieve(scwin.rentloanNo,scwin.rentloanSeq);
    }else{
        ds_out.insertRow();
        ds_out.setRowPosition(0);
        scwin.f_OnLoad_done();
        scwin.f_RentloanShapeCdChange();
    }

    if(scwin.rentloanNo == undefined && scwin.rentloanSeq == undefined){
        ed_rentloanNo.setValue("");
    }else{
        ed_rentloanNo.setValue(scwin.rentloanNo + "-" + scwin.rentloanSeq);
    }

    dlt_commonCodeZZ913.sort("cd", 0);
    dlt_commonCodeZZ912.sort("cd", 0);

    ed_regAreaM2.setValue(0);
    ed_regAreaPy.setValue(0);
    ed_rentloanAreaM2.setValue(0);
    ed_rentloanAreaPy.setValue(0);
    ed_xclsRt.setValue(0);

};

scwin.popTitleCh = function() {
    $c.data.setPopupTitle("임대차[전대차] 계약기본정보");
};

// f_OnLoad에서 실행되지만 조회후 처리할 작업 모음
scwin.f_OnLoad_done = function() {
    scwin.hid_rsltsStDt = ds_out.getCellData(0, "rsltsStDt");
    scwin.hid_rentloanEndDt = ds_out.getCellData(0, "rentloanEndDt");
    scwin.rentloanNo = ds_out.getCellData(0, "rentloanNo");
    scwin.rentloanSeq = ds_out.getCellData(0, "rentloanSeq");
    scwin.uppermostBizDomCd = scwin.hid_uppermostBizDomCd;

    if(ds_out.getCellData(0, "ownerCnsntYn")=="1"){
        btn_ownerEvid.show();
        tr_id1.show();
    }else{
        btn_ownerEvid.hide();
        tr_id1.hide();
    }

    if(scwin.uppermostBizDomCd == "200" &&
        (lc_rentloanShapeCd.getValue() == "03" || lc_rentloanShapeCd.getValue() == "04")
    ){
        tr_for200.show("table-row");

    }else{
        tr_for200.hide();
    }

    ///////////////////////////
    scwin.f_OnLoad_done_after();
};

scwin.f_OnLoad_done_after = function() {
    totalRows.setValue(ds_out2.getRowCount());
    if(ds_out.getRowCount() == 0){
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        scwin.f_DisableRantInfo();
    }

    if(scwin.rentloanKbn != "NEW") {
        $c.gus.cfDisableObjects([lc_rentloanShapeCd]);
    } else {
        $c.gus.cfEnableObjects([lc_rentloanShapeCd,lc_rentloanCond]);
    }

    $c.gus.cfDisableObjects([btn_termination]);

    if(scwin.popYn == 'Y')	
    // 팝업으로 넘어오는 항목인 경우 목록 버튼 비활성화
	{
		$c.gus.cfDisableObjects([btn_save, btn_list]);
	}

    //신규일 경우...
    if(scwin.rentloanKbn == "NEW") {
        acctDeptCd.setValue(scwin.acctDeptCd);
        acctDeptNm.setValue(scwin.acctDeptNm);

        //계약체결일, 계약개시일, 계약종료일 enable
        $c.gus.cfEnableObjects([ed_rentloanConcDt]);
        $c.gus.cfEnableObjects([ed_rentloanStDt]);      
        $c.gus.cfEnableObjects([ed_rentloanEndDt]);    

        //실시작일자, 실종료일자 disable
        $c.gus.cfDisableObjects([ed_rsltsStDt]);
        //$c.gus.cfDisableObjects([ed_rsltsEndDt]);   

        //계약구분 - 신규
        ds_out.setCellData(0, "rentloanClsCd", "01"); 
        $c.gus.cfDisableObjects([lc_rentloanClsCd]);

        $c.gus.cfDisableObjects([pu_place,pu_path,pu_rate,ChainedISNm,pu_img]);
        $c.gus.cfDisableObjects([btn_termination,ed_closeDt]);

        //계약해제버튼
	    $c.gus.cfDisableObjects([btn_ctrtEnd]);

        if(ds_out.getCellData(0, "dcsnYn") == "1") {
	        $c.gus.cfDisableObjects([btn_comp]);
	        $c.gus.cfEnableObjects([btn_cancel]);
	    }
	    else {
	        $c.gus.cfDisableObjects([btn_cancel]);	        
	        $c.gus.cfDisableObjects([btn_comp]);
	    }

	    scwin.f_addRow();
	    ds_out.setCellData(0, "rentloanShapeCd", "01");
    } 

    //변경일 경우...
    if(scwin.rentloanKbn == "CHG") {
        //계약체결일, 계약개시일, 계약종료일, 실종료일자 Disable
        $c.gus.cfDisableObjects([ed_rentloanConcDt]);
        $c.gus.cfDisableObjects([ed_rentloanStDt]);   
        $c.gus.cfDisableObjects([ed_rentloanEndDt]);    

        //실시작일자  enable
        $c.gus.cfEnableObjects([ed_rsltsStDt]);

        //계약구분 - 변경
        ds_out.setCellData(0, "rentloanClsCd", "02"); 
        $c.gus.cfDisableObjects([lc_rentloanClsCd]);

        $c.gus.cfDisableObjects([pu_place,pu_path,pu_rate,ChainedISNm,pu_img]);

        $c.gus.cfDisableObjects([btn_comp]);
        $c.gus.cfDisableObjects([btn_cancel]);
        $c.gus.cfDisableObjects([btn_termination,ed_closeDt]);

        //계약해제버튼
	    $c.gus.cfDisableObjects([btn_ctrtEnd]);
    }

    //갱신일 경우...
    if(scwin.rentloanKbn == "REN") {
        //계약체결일, 계약개시일, 계약종료일 enable        
        $c.gus.cfEnableObjects([ed_rentloanConcDt]);      
        $c.gus.cfEnableObjects([ed_rentloanStDt]);      
        $c.gus.cfEnableObjects([ed_rentloanEndDt]);    
        //실시작일자, 실종료일자 disable
        $c.gus.cfDisableObjects([ed_rsltsStDt]);

        //계약구분 - 갱신
        ds_out.setCellData(0, "rentloanClsCd", "03"); 
        $c.gus.cfDisableObjects([lc_rentloanClsCd]);

        $c.gus.cfDisableObjects([pu_place,pu_path,pu_rate,ChainedISNm,pu_img]);


        $c.gus.cfDisableObjects([btn_comp]);
        $c.gus.cfDisableObjects([btn_cancel]);
        $c.gus.cfDisableObjects([btn_termination,ed_closeDt]);

        //계약해제버튼
	    $c.gus.cfDisableObjects([btn_ctrtEnd]);

        ed_rsltsStDt.setValue("");
    }

    //수정일 경우 
    if(scwin.rentloanKbn == "MOD") {
        //계약체결일, 계약개시일, 계약종료일, 실시작일자, 실종료일자  disable
        if(ds_out.getCellData(0, "dcsnYn") == "0" && (ds_out.getCellData(0, "rentloanClsCd") == "01" || ds_out.getCellData(0, "rentloanClsCd") == "03")) {
            $c.gus.cfEnableObjects([ed_rentloanConcDt]);
            $c.gus.cfEnableObjects([ed_rentloanStDt]);      
            $c.gus.cfEnableObjects([ed_rentloanEndDt]);
        }
        else {        
	        $c.gus.cfDisableObjects([ed_rentloanConcDt]);      
	        $c.gus.cfDisableObjects([ed_rentloanStDt]);      
	        $c.gus.cfDisableObjects([ed_rentloanEndDt]);
        }            
        $c.gus.cfDisableObjects([ed_rsltsStDt]);
        $c.gus.cfDisableObjects([lc_rentloanClsCd]); 

        $c.gus.cfEnableObjects([pu_path,pu_rate,ChainedISNm,pu_img]);

        // 임대 전대일때 담보버튼 비활성화
        if(lc_rentloanShapeCd.getValue() == "03" || lc_rentloanShapeCd.getValue() == "04"){
            $c.gus.cfDisableObjects([pu_place]);
        }else{
            $c.gus.cfEnableObjects([pu_place]);
        }   

        if(ds_out.getCellData(0, "dcsnYn") == "1") {
            $c.gus.cfDisableObjects([btn_comp]);
            $c.gus.cfEnableObjects([btn_cancel]);
            $c.gus.cfDisableObjects([ed_clntNo,acctDeptCd,btn_acctDeptCd,cls_acctDeptCd,ed_clntNm,btn_cIntCd,lc_usePurpsCd,lc_rentloanCond,btn_loanCtrtNo,cls_loanCtrtNo,chk_ownerCnsnt]);
        } else {
            $c.gus.cfDisableObjects([btn_cancel]);
            $c.gus.cfEnableObjects([btn_comp]);
            $c.gus.cfEnableObjects([ed_clntNo,acctDeptCd,btn_acctDeptCd,cls_acctDeptCd,ed_clntNm,btn_cIntCd,lc_usePurpsCd,lc_rentloanCond,btn_loanCtrtNo,cls_loanCtrtNo,chk_ownerCnsnt]);
        }

        //최종승인상태일시 해재가능.
        if(ds_out.getCellData(0, "apprvStsCd") == "05" && !(ds_out.getCellData(0, "rentloanClsCd") == "04"))
            $c.gus.cfEnableObjects([btn_termination,ed_closeDt]);
        else
            $c.gus.cfDisableObjects([btn_termination,ed_closeDt]);

	    //계약해제버튼
        if(ds_out.getCellData(0, "apprvStsCd") == "05" && ds_out.getCellData(0, "rentloanClsCd") != "04") {
			if(ed_rentloanEndDt.getValue() > scwin.sDate) {
			    $c.gus.cfDisableObjects([btn_ctrtEnd]);
			} else {
			    $c.gus.cfEnableObjects([btn_ctrtEnd]);
			}
		} else {
		    $c.gus.cfDisableObjects([btn_ctrtEnd]);
		}
    }

    // 임대일 경우
    if(lc_rentloanShapeCd.getValue() == "03") {
        $c.gus.cfDisableObjects([ btn_loanCtrtNo,cls_loanCtrtNo]);
        $c.gus.cfEnableObjects([btn_fixedAsetNo]);
        if(ds_out2.getRowCount() > 0) {
            $c.gus.cfDisableObjects([ed_regAreaM2,ed_regAreaPy]);
        }
    }    
    // 전대일 경우
    else if(lc_rentloanShapeCd.getValue() == "04") {
        if(ds_out.getCellData(0, "dcsnYn") != "1"){
            $c.gus.cfEnableObjects([btn_loanCtrtNo,cls_loanCtrtNo]);
            $c.gus.cfDisableObjects([btn_fixedAsetNo]);
            ed_fixedAsetNo.setValue("");
            ed_fixedAsetNm.setValue("");
        }    
        if(ds_out2.getRowCount() > 0){ 
            $c.gus.cfEnableObjects([ed_regAreaM2,ed_regAreaPy]);
        }
    }
    // 임차, 전차일 경우
    else {
        if(ds_out2.getRowCount() > 0){
            $c.gus.cfEnableObjects([ed_regAreaM2,ed_regAreaPy]);
        }else{
            $c.gus.cfDisableObjects([ed_regAreaM2,ed_regAreaPy]);
        }    
    }

    scwin.f_RentloanShapeCdChange();

    if(ds_out.getCellData(0, "rentloanClsCd") == "04"){
        $c.gus.cfDisableObjects([btn_save]);
    }

    //상세주소1 disable
    $c.gus.cfDisableObjects([ed_addr1_1]);
    $c.gus.cfDisableObjects([ed_rentloanPicAddr1]);
    $c.gus.cfDisableObjects([ed_bilgAdjmPicAddr1]);

    //자산 명 disable
    $c.gus.cfDisableObjects([ed_fixedAsetNm]);

    // 갱신 계약번호 disable
    $c.gus.cfDisableObjects([ed_renBfRentloanNo]);

    //귀속부서명 disable
    $c.gus.cfDisableObjects([acctDeptNm]);

    //입력필드 IME한글
    //cfSetIMEModeActiveObjects([txt_clntNm, txt_addr1_2, txt_rentloanPicAddr2, txt_bilgAdjmPicAddr2]);
    //imeMode active 속성부여

    //승인상태일시 확정취소 불가.
    if(!(ds_out.getCellData(0, "apprvStsCd") == "01" || ds_out.getCellData(0, "apprvStsCd") == "03")){
        $c.gus.cfDisableObjects([btn_cancel]);
    }     

    //scwin.f_ApplyownerCnsnt(); 

    $c.gus.cfDisableObjects([ed_loanCtrtNo, ed_fixedAsetNo]);	

    scwin.hid_uppermostBizDomCd = scwin.uppermostBizDomCd;

    //여객이고 임대/전대인 경우
    if(scwin.uppermostBizDomCd == "200" && (lc_rentloanShapeCd.getValue() == "03" || lc_rentloanShapeCd.getValue() == "04")){
    	ed_mgntPmntDd.options.mandatory = "true";
    }
    else
    {
    	ed_mgntPmntDd.options.mandatory = "false";
    }

};



	//-------------------------------------------------------------------------
	// Dataset DEBUG
	//-------------------------------------------------------------------------
scwin.dataSetDebug = function() {

};

scwin.f_DisableRantInfo = function() {
    $c.gus.cfDisableObjects([lc_goodsCd]);
    $c.gus.cfDisableObjects([lc_posnClsCd]);
    $c.gus.cfDisableObjects([ed_zip,btn_zip]);

    $c.gus.cfDisableObjects([ed_addr1_2]);
    $c.gus.cfDisableObjects([lc_bldgStucNm]);
    $c.gus.cfDisableObjects([ed_topFloor]);
    $c.gus.cfDisableObjects([ed_bottomFloor]);
    $c.gus.cfDisableObjects([ed_buildYy,btn_buildYy]);
    $c.gus.cfDisableObjects([ed_lotNo]);
    $c.gus.cfDisableObjects([ed_regAreaM2]);
    $c.gus.cfDisableObjects([ed_regAreaPy]);
    $c.gus.cfDisableObjects([ed_rentloanAreaM2]);
    $c.gus.cfDisableObjects([ed_rentloanAreaPy]);
    $c.gus.cfDisableObjects([ed_xclsRt]);   
    $c.gus.cfDisableObjects([ed_fixedAsetNo, btn_fixedAsetNo]);
    ed_fixedAsetNo.setValue("");
    ed_fixedAsetNm.setValue("");
};

scwin.f_EnableRantInfo = function() {

};

scwin.f_HeaderCreate = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
};

    //-------------------------------------------------------------------------
    // function name : f_grdHeiht
    // function desc : 그리드 높이 늘리기
    // function Parameter : null
    //-------------------------------------------------------------------------
scwin.f_grdHeiht = function() {

};

  //-------------------------------------------------------------------------
  // 조회
  //-------------------------------------------------------------------------
scwin.f_Retrieve = function(rentloanNo,rentloanSeq) { 
    let condition = "";
    condition = "?rentloanNo=" + rentloanNo + "&rentloanSeq=" + rentloanSeq;
    sbm_tr_retrieve.action = "/cm.bc.rentloan.RetrieveRentLoanContractBasisInformationCMD.do" + condition; 
    $c.sbm.execute(sbm_tr_retrieve);
};

  //-------------------------------------------------------------------------
  // 화면이동
  //-------------------------------------------------------------------------
// 버튼6개 
scwin.f_winOpen = function (strIndex) {
    let strPath = "";
    let vRentloanShapeCd = lc_rentloanShapeCd.getValue();
    scwin.uppermostBizDomCd = scwin.hid_uppermostBizDomCd;

    let menuInfo = null;
    let pgmId = "";

    if ($p && typeof $c.data.getParameter === "function") {
        menuInfo = $c.data.getParameter($p, "menuInfo");
        pgmId = $c.data.getParameter($p, "menuInfo").pgmId;
    }


    let rentloan = ds_out.getCellData(0, "rentloanNo")+ds_out.getCellData(0, "rentloanSeq");

    let data = {};
    data.mode = "MOD";
    data.cf = scwin.cfValue;
    data.selBizDom = scwin.uppermostBizDomCd;
    data.rentloanNo = ds_out.getCellData(0, "rentloanNo");
    data.rentloanSeq = ds_out.getCellData(0, "rentloanSeq");

    let opt = {};
    opt.width = "2500";
    opt.height = "1300";
    opt.modal = true;
    opt.title = "title";
    opt.id = "popup";

    switch (strIndex)
        {
            case 0:
                if(scwin.popYn == 'Y'){

                    data.popYn = "Y";
                    opt.popupName = "계약기본정보";

                    let sURL = "/ui/cm/bc/rentloan/zz_900_01_02b.xml";
                    $c.win.openPopup(sURL, opt, data);
                }else{
