    //-------------------------------------------------------------------------
    // function name : f_addRow
    // function desc : 행추가
    // function Parameter : objGrd : 그리드
    //-------------------------------------------------------------------------
// 행추가
scwin.f_addRow = function() {
    if(btn_save.getDisabled()){
        return;
    }else{
        let row = ds_out2.insertRow();
        if(row == 0){
            ds_out2.setRowPosition(0);
            $c.gus.cfGoPrevPosition(gr_out2, 0);
        }else{
            $c.gus.cfGoPrevPosition(gr_out2, row);
        }

        ds_out2.setCellData(row, "rentloanNo", scwin.rentloanNo);
        ds_out2.setCellData(row, "rentloanSeq", scwin.rentloanSeq);

        scwin.f_EnableRantInfo();
    }
};

// 행삭제
scwin.f_DelRow = function() {
    if(btn_save.getDisabled()){
        return;
    }else{
        let nowRow = ds_out2.getRowPosition();
        let sts = ds_out2.getRowStatus(gr_out2.getFocusedRowIndex());
        if(nowRow != null){
            if(sts == "C") {
                ds_out2.removeRow(nowRow);
                $c.gus.cfGoPrevPosition(gr_out2, nowRow-1);
            }else if(sts == "D"){
                //아무동작 하지 않음
            }else{
                ds_out2.deleteRow(nowRow);
                $c.gus.cfGoPrevPosition(gr_out2, nowRow);
                //gr_out2.setRowDisabled(nowRow, true);
            }
        }
        if(ds_out2.getRowCount() < 0){
            scwin.f_DisableRantInfo();
        }
    }
};

// 행취소
scwin.f_cancelRow = function() {
    if(btn_save.getDisabled()){
        return;
    }else{
        let nowRow = ds_out2.getRowPosition();
        let sts = ds_out2.getRowStatus(gr_out2.getFocusedRowIndex());
        if(nowRow != null){
            if(sts == "C") {
                ds_out2.removeRow(nowRow);
                $c.gus.cfGoPrevPosition(gr_out2, nowRow-1);
            }else{
                ds_out2.undoRow(nowRow);
            }
        }
        if(ds_out2.getRowCount() < 0){
            scwin.f_DisableRantInfo();
        }
    }
};

    //-------------------------------------------------------------------------
    // 저장
    //-------------------------------------------------------------------------
// 저장
scwin.f_Save = async function() {
    let sMsg = "";

    if (  scwin.entloanKbn == "CHG" || scwin.rentloanKbn == "REN") {
        ds_out.setCellData(0, "chgModFlag", "Y");
        for (i = 0; i < ds_out2.getRowCount(); i++) 
            ds_out2.setCellData(i, "chgModFlag", "Y");

        if ( scwin.rentloanKbn == "CHG" ) {

            // 실 시작일자는 계약개시일, 계약종료일 범위를 넘을 수 없음.
            if( !(ds_out.getCellData(0, "rsltsStDt") > ds_out.getCellData(0, "rentloanStDt") &&
                ds_out.getCellData(0, "rsltsStDt") < ds_out.getCellData(0, "rentloanEndDt")) ) 
            {
                await $c.win.alert("실 시작일자는 계약개시일, 계약종료일 범위 사이에 있어야 합니다.");
                ed_rsltsStDt.focus();
                return;
            }

            // 실 시작일은 반드시 변경되어야 함.
            if( ds_out.getCellData(0, "rsltsStDt") == scwin.hid_rsltsStDt ) {
                await $c.win.alert("계약 변경시 실 시작일자는 반드시 변경되어야 합니다..");
                ed_rsltsStDt.focus();
                return;
            }
        }
    }

    if ( ds_out.getModifiedIndex().length > 0 == false  && ds_out2.getModifiedIndex().length > 0 == false)
    {
        await $c.win.alert("변경된 데이타가 없습니다.");
        return;
    }

    if( ds_out.getCellData(0, "rsltsStDt") >= ds_out.getCellData(0, "rsltsEndDt") && !(scwin.rentloanKbn == "NEW" ||  scwin.rentloanKbn == "REN" || scwin.rentloanKbn == "CHG")) {
        await $c.win.alert("[실시작일자]는 [실종료일자]보다 작아야 합니다.");
        ed_rsltsStDt.focus();
        return;
    } 

    if( ds_out.getCellData(0, "rentloanStDt") >= ds_out.getCellData(0, "rentloanEndDt") ) {
        await $c.win.alert("[계약개시일자]는 [계약종료일자]보다 작아야 합니다.");
        ed_rentloanStDt.focus();
        return;
    } 

    if( ds_out.getCellData(0, "clntNo") == "" ) 
    {
        await $c.win.alert("[계약거래처]는 필수입력항목입니다.");
        ed_clntNo.focus();
        return;
    }

    if( ds_out.getCellData(0, "rentloanConcDt") == "" ) 
    {
        await $c.win.alert("[계약체결일]은 필수입력항목입니다.");
        ed_rentloanConcDt.focus();
        return;
    }

    if( ds_out.getCellData(0, "rentloanStDt") < ds_out.getCellData(0, "rentloanConcDt") ) {
        await $c.win.alert("[계약체결일자]는 [계약개시일자]보다 작거나 같아야 합니다.");
        ed_rentloanConcDt.focus();
        return;
    } 

    if( ds_out.getCellData(0, "rentloanStDt") == "" ) 
    {
        await $c.win.alert("[계약개시일]은 필수입력항목입니다.");
        ed_rentloanStDt.focus();
        return;
    }

    if( ds_out.getCellData(0, "rentloanEndDt") == "" ) 
    {
        await $c.win.alert("[계약종료일]은 필수입력항목입니다.");
        ed_rentloanEndDt.focus();
        return;
    }

    if( ds_out.getCellData(0, "rsltsStDt") == "" && !(scwin.rentloanKbn == "NEW" ||  scwin.rentloanKbn == "REN")) 
    {
        await $c.win.alert("[실시작일자]는 필수입력항목입니다.");
        ed_rentloanStDt.focus();
        return;
    }

    if( ds_out.getCellData(0, "rsltsEndDt") == "" && !(scwin.rentloanKbn == "NEW" ||  scwin.rentloanKbn == "REN")) 
    {
        await $c.win.alert("[실종료일자]는 필수입력항목입니다.");
        ed_rentloanEndDt.focus();
        return;
    }

    if( ds_out.getCellData(0, "rentloanClsCd") == "" ) 
    {
        await $c.win.alert("[계약구분]은 필수입력항목입니다.");
        lc_rentloanClsCd.focus();
        return;
    }

    if( ds_out.getCellData(0, "rentloanShapeCd") == "" ) 
    {
        await $c.win.alert("[계약형태]는 필수입력항목입니다.");
        lc_rentloanShapeCd.focus();
        return;
    }

    if( ds_out.getCellData(0, "rentloanCond") == "" ) 
    {
        await $c.win.alert("[계약조건]은 필수입력항목입니다.");
        lc_rentloanCond.focus();
        return;
    }

    if( ds_out.getCellData(0, "acctDeptCd") == "" ) 
    {
        await $c.win.alert("[귀속부서]는 필수입력항목입니다.");
        acctDeptCd.focus();
        return;
    }

    if(lc_rentloanShapeCd.getValue() == "03") {
        if(!(ds_out2.getRowCount() > 0)) {
            await $c.win.alert("임대일 경우 부동산정보는 하나 이상 필수입력항목입니다.");
            return;
        }
    }

    if(lc_rentloanShapeCd.getValue() == "04") {
        if(ed_loanCtrtNo.getValue().trim() == "") {
            await $c.win.alert("전대일 경우 임/전차 계약번호는 필수입력항목입니다.");
            $c.gus.cfEnableObjects([ed_loanCtrtNo]);
            ed_loanCtrtNo.focus();
            return;
        }
    }

    for (i = 0; i < ds_out2.getRowCount(); i++)
    {
        //필수항목 Check - 부동산구분
        if( ds_out2.getCellData(i, "goodsCd") == "" ) 
        {
            await $c.win.alert("[부동산구분]은 필수입력항목입니다.");
            lc_goodsCd.focus();
            return;
        }


        //필수항목 Check - 우편번호
        if( ds_out2.getCellData(i, "zip") == "" ) 
        {
            await $c.win.alert("[우편번호]은 필수입력항목입니다.");
            ed_zip.focus();
            return;
        }

        //필수항목 Check - 상세주소1
        if( ds_out2.getCellData(i, "addr1") == "" ) 
        {
            await $c.win.alert("[상세주소1]은 필수입력항목입니다.");
            return;
        }

        //필수항목 Check - 상세주소2
        if( ds_out2.getCellData(i, "addr2") == "" ) 
        {
            await $c.win.alert("[상세주소2]은 필수입력항목입니다.");
            ed_addr1_2.focus();
            return;
        }

        if(lc_rentloanShapeCd.getValue() == "03" || lc_rentloanShapeCd.getValue() == "04") {
            if( ds_out2.getCellData(i, "rentloanAreaM2") == "" || ds_out2.getCellData(i, "rentloanAreaM2") == "0" ) 
            {
                await $c.win.alert("[계약기준면적(m²)]은 필수입력항목입니다.");
                ed_rentloanAreaM2.focus();
                return;
            }

            if( ds_out2.getCellData(i, "rentloanAreaPy") == "" || ds_out2.getCellData(i, "rentloanAreaPy") == "0" ) 
            {
                await $c.win.alert("[계약기준면적(평)]은 필수입력항목입니다.");                    
                ed_rentloanAreaPy.focus();
                return;
            }
        }

        if(lc_rentloanShapeCd.getValue() == "03") {
            if( ds_out2.getCellData(i, "fixedAsetNo") == "" ) {
                await $c.win.alert("임대일 경우 [자산번호]는 필수 입력항목입니다.");
                return;
            }
        }

        //여객이고 임대/전대인 경우
        if(scwin.uppermostBizDomCd == "200" && (lc_rentloanShapeCd.getValue() == "03" || lc_rentloanShapeCd.getValue() == "04")){

            if( ed_mgntPmntDd.getValue() == 0 ) 
            {
                await $c.win.alert("관리비납부일은(는) 필수 입력 항목입니다.");
                ed_mgntPmntDd.focus();
                return;
            }	

            if(ed_tmlNm.getValue() == "" ){
                ed_tmlNm.setValue(".");
            }
        }

    };          

    if ( scwin.rentloanKbn == "CHG"){ 
        sMsg = "변경하시겠습니까?";
    }
    else if ( scwin.rentloanKbn == "REN"){
        sMsg = "갱신하시겠습니까?";
    }    
    else if ( scwin.rentloanKbn == "MOD"){
        sMsg = "수정하시겠습니까?";
    }    
    else if ( scwin.rentloanKbn == "DEL"){
        sMsg = "삭제하시겠습니까?";
    }    
    else{
        sMsg = "저장하시겠습니까?";
    }    

    if (await $c.win.confirm(sMsg) ){

        for(let i=0; i< ds_out.getRowCount(); i++){
            ds_out.setCellData(i, "rentloanKbn", scwin.rentloanKbn);
        }
        for(let i=0; i< ds_out2.getRowCount(); i++){
            ds_out2.setCellData(i, "rentloanKbn", scwin.rentloanKbn);
        }
        //sbm_tr_save.action = condition;            
        $c.sbm.execute(sbm_tr_save);
    }    
};

    //-------------------------------------------------------------------------
    // 확정취소
    //-------------------------------------------------------------------------
scwin.f_ctrtCancel = async function() {
    if ( !(ds_out.getModifiedIndex().length > 0 == false  && ds_out2.getModifiedIndex().length > 0 == false)) {
        if (await $c.win.confirm("변경된 내역이 있습니다. 저장하시겠습니까?") ){
            for(let i=0; i< ds_out.getRowCount(); i++){
                ds_out.setCellData(i, "rentloanKbn", "MOD");
            }
            for(let i=0; i< ds_out2.getRowCount(); i++){
                ds_out2.setCellData(i, "rentloanKbn", "MOD");
            }
            //sbm_tr_save.action = condition;            
            $c.sbm.execute(sbm_tr_save);
        }
    }

    let confirm = await $c.win.confirm("계약확정을 취소하시겠습니까?")
        if( confirm ) {
            ds_out.setCellData(0, "dcsnYn", "0");
            $c.sbm.execute(sbm_tr_ctrtreg);
        }
};

    //-------------------------------------------------------------------------
    // 계약해지
    //-------------------------------------------------------------------------
scwin.f_ctrtClose = async function() {
    if ( !(ds_out.getModifiedIndex().length > 0 == false  && ds_out2.getModifiedIndex().length > 0 == false)) {
        if (await $c.win.confirm("변경된 내역이 있습니다. 저장하시겠습니까?") ){
            for(let i=0; i< ds_out.getRowCount(); i++){
                ds_out.setCellData(i, "rentloanKbn", "MOD");
            }
            for(let i=0; i< ds_out2.getRowCount(); i++){
                ds_out2.setCellData(i, "rentloanKbn", "MOD");
            }
            //sbm_tr_save.action = condition;            
            $c.sbm.execute(sbm_tr_save);
        }
    }

    if( ed_closeDt.getValue() ==  "" ) 
    {
        await $c.win.alert("[해지일자]는 필수입력항목입니다.");
        ed_closeDt.focus();
        return;
    }

    if( ds_out.getCellData(0, "rsltsStDt") > ed_closeDt.getValue() )
    {
        await $c.win.alert("[해지일자]는 [실시작일자]보다 커야합니다.");
        ed_closeDt.focus();
        return;
    }

    if( ds_out.getCellData(0, "rsltsEndDt") < ed_closeDt.getValue() )
    {
        await $c.win.alert("[해지일자]는 [실종료일자]보다 작아야합니다.");
        ed_closeDt.focus();
        return;
    }

    if (await $c.win.confirm("계약을 해지하시겠습니까?") ){ 
        ds_out.setCellData(0, "closeState", "CHK");
        $c.sbm.execute(sbm_tr_ctrtclose);
    }

};

