scwin.f_ctrtEnd = async function() {
    /* ASIS 작동하지 않음
    if($c.gus.cfIsAfterDate(ds_out.getCellData(0, "rsltsEndDt"), scwin.sDate)){
        await $c.win.alert("계약해지는 현재일보다 계약종료일이 큰경우에 처리 가능합니다.");
        return;
    }
