	//-------------------------------------------------------------------------
	// function name : f_openCommonPopUp
	// function desc : popup
	//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let pCtrtNo = ed_loanCtrtNo.getValue();
    if(pCode!= ""){
        pName = "";
    }
    switch (disGubun)
    {
        //거래처 조회
        case 1: 
            udc_clntList.cfCommonPopUp(scwin.udc_clntList_callBackFunc
                                        ,pCode                  // 화면에서의 ??? Code Element의  Value
                                        ,pName                  // 화면에서의 ??? Name Element의  Value
                                        ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                                        ,'5'                    // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                                        ,null                   // Title순서  
                                        ,'150,170'              // 보여주는 각 컬럼들의 폭    
                                        ,'3,4,5,6,7,8,9,10'     // 컬럼중에서 숨기는    컬럼 지정   
                                        ,',RENTLOAN_CLNT'                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                        ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                                        ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                                        ,null                   // 윈도우 위치 Y좌표   
                                        ,null                   // 윈도우 위치 X좌표
                                        ,null                   // 중복체크여부   ("F")
                                        ,pAllSearch             // 전체검색허용여부 ("F")
                                        ,'거래처 조회,거래처코드 ,거래처명 '                  // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                        );
        break;
        //임/전차 계약번호 조회       
        case 2: 
            udc_rentloanList.cfCommonPopUp(scwin.udc_rentloanList_callBackFunc
                                        ,pCode                  	// 화면에서의 ??? Code Element의  Value
	                                    ,''                  		// 화면에서의 ??? Name Element의  Value
	                                    ,pClose                 	// 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
	                                    ,null                    	// 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
	                                    ,null                   	// Title순서  
	                                    ,null                 		// 보여주는 각 컬럼들의 폭    
	                                   ,'2,7,8,9,10'     			// 컬럼중에서 숨기는    컬럼 지정   
	                                    ,',,'+scwin.uppermostBizDomCd     // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
	                                    //,'3'                   		// SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
	                                    ,null                   	// POP-UP뛰을때 원도우의   사용자 정의  폭
	                                    ,null                   	// POP-UP뛰을때 우도우의   사용자 정의  높이  
	                                    ,null                   	// 윈도우 위치 Y좌표   
	                                    ,null                   	// 윈도우 위치 X좌표
	                                    ,null                   	// 중복체크여부   ("F")
	                                    ,pAllSearch             	// 전체검색허용여부 ("F")
	                                    ,null                 		// POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
	                                    ,null
	                                    ,null
	                                    ,pCtrtNo   //19
                                        );


        /* pCallback, pCode, pName, pWinCloseTF, pDispCnt, pTitle, pWidth, pHidden, pWhere, pW, pH, pTop, pLeft, pExistTF, pAllSearchTF, pWtitleSearch, pNoDataCloseTF, tmpDataSet, pYear                                 */
        break;
        //귀속부서
        case 3: 
            udc_acctDeptCdInfo.cfCommonPopUp(scwin.udc_acctDeptCdInfo_callBackFunc
            ,pCode,pName,"T",null,null,null,"3,4,5,6,7,8,9,10",null,null,null,null,null,null,null,"귀속부서, 귀속부서코드, 귀속부서명",null); 

        break;

    default:
  	break;        
    }
};

