scwin.f_asetPopup = function(cdObjNm, nmObjNm, isCdYn) {
    if(lc_goodsCd.getValue() == "01" ){
        isCdYn = '05';
    }else if(lc_goodsCd.getValue() == ""){
        isCdYn = '10';
    }else{
        isCdYn = '10';
    }

    let data = {
        cdObjNm : cdObjNm.getValue(),
        nmObjNm : nmObjNm.getValue(),
        isCdYn : isCdYn,
        callbackFn: scwin.aset_callBackFunc
    };

    let opts = {
        id : "aset",	
        modal : true,
        popupName : "임대 자산 팝업",
        type : "browserPopup" ,
        title : "pop",
        width : 2200,
        height : 800
    }
    $c.win.openPopup("/ui/cm/bc/rentloan/zz_900_05_01p.xml", opts, data);

};

scwin.aset_callBackFunc = function(rtnList) {
    if(rtnList != null ) {
        ed_fixedAsetNo.setValue(rtnList.fixedAsetNo);
        ed_fixedAsetNm.setValue(rtnList.fixedAsetNm);
        ed_regAreaM2.setValue(rtnList.area);
        ed_regAreaPy.setValue(parseInt(parseInt(rtnList.area) * 0.3025) );
    }
    if(rtnList.asetPatternCd == '05'){    
        lc_goodsCd.setValue("01");
    }else{
        lc_goodsCd.setValue("02");
    }

};

