// 목록
scwin.cfTabMenuAdd = function() {
    let sURL = scwin.strBasSdId;
    $c.win.openMenu('계약관리', sURL,sURL.substring(sURL.lastIndexOf("/") + 1).replace(/.xml/g,"")+".jsp");
};

scwin.cfTabMenuCurrentUpdate = function(url,name) {
    let rentloan = ds_out.getCellData(0, "rentloanNo")+ds_out.getCellData(0, "rentloanSeq");
    let sURL = url.split("?")[0];
    let dataString = url.split("?")[1];
    let data = {};
    if (dataString) {
        dataString.split("&").forEach(function (param) {
            let keyValue = param.split("=");
            let key = keyValue[0];
            let value = keyValue[1];
            data[key] = value;
        });
    }
    $c.win.openMenu(name,sURL,sURL.substring(sURL.lastIndexOf("/") + 1).replace(/.xml/g,"")+".jsp",data,{openAction : "exist", menuCode : rentloan, menuCode2 : "new"});
};

// 최상위사업영역 서브미션
scwin.sbm_ds_uppermostBizdom_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    if(ds_uppermostBizdom.getCellData(0, "col1") != "N/A" && ds_uppermostBizdom.getCellData(0, "col1") != "000" ){
        if(scwin.selBizDom == "" || scwin.selBizDom == null){
            scwin.uppermostBizDomCd = ds_uppermostBizdom.getCellData(0, "col1");
        }else{
            scwin.uppermostBizDomCd = scwin.selBizDom;
        }        
    }else{
        scwin.uppermostBizDomCd = "252";
    }
    scwin.hid_uppermostBizDomCd = scwin.uppermostBizDomCd;	
};

// 최상위사업영역
scwin.f_uppermostBizdom = function() {
    const params = {
        sysCd: "CommonEBC",
        queryId: "retrieveUppermostBizDomInfo",
        param1: scwin.memJson.empNo
    };
    dma_uppermostBizdom_param.setJSON(params);
    $c.sbm.execute(sbm_ds_uppermostBizdom);
};

// 서브미션
scwin.sbm_tr_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    ds_out.setRowPosition(0);
    $c.gus.cfGoPrevPosition(gr_out2, 0);

    $p.setTimeout(function() {
        scwin.f_OnLoad_done();
        scwin.f_RentloanShapeCdChange();
    }, {"delay":50});

    scwin.uppermostBizDomCd = scwin.hid_uppermostBizDomCd;
    if((ds_out.getCellData(0, "dcsnYn") == 0 && (scwin.rentloanKbn == "REN" || scwin.rentloanKbn == "CHG")) || (ds_out.getCellData(0, "rentloanClsCd") == "04") && (scwin.rentloanKbn == "REN" || scwin.rentloanKbn == "CHG")) {
        let strPath = "/ui/cm/bc/rentloan/zz_900_01_02b.xml?mode=MOD&cf="+scwin.cfValue+"&rentloanNo="+scwin.rentloanNo+"&rentloanSeq="+scwin.rentloanSeq+"&selBizDom="+scwin.uppermostBizDomCd;
        scwin.cfTabMenuCurrentUpdate( strPath , "계약-수정") ;
    } 
};

// 서브미션
scwin.sbm_tr_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.uppermostBizDomCd = scwin.hid_uppermostBizDomCd;
    if(scwin.popYn == 'Y'){
        scwin.ondataload();
    }else{
        let strPath = "/ui/cm/bc/rentloan/zz_900_01_02b.xml?mode=MOD&cf="+scwin.cfValue+"&rentloanNo="+ds_out3.getCellData(0, "rentloanNo")+"&rentloanSeq="+ds_out3.getCellData(0, "rentloanSeq")+"&selBizDom="+scwin.uppermostBizDomCd;
        scwin.cfTabMenuCurrentUpdate( strPath , "계약-수정") ;
    }
};

// 서브미션
scwin.sbm_tr_ctrtreg_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 ){
        $c.gus.cfAlertMsg(MSG_CM_INF_001);
        scwin.uppermostBizDomCd = scwin.hid_uppermostBizDomCd;
        if(scwin.popYn == 'Y'){
            scwin.ondataload();
        }else{
            let strPath = "/ui/cm/bc/rentloan/zz_900_01_02b.xml?mode=MOD&cf="+scwin.cfValue+"&rentloanNo="+scwin.rentloanNo+"&rentloanSeq="+scwin.rentloanSeq+"&selBizDom="+scwin.uppermostBizDomCd;
            scwin.cfTabMenuCurrentUpdate( strPath , "계약-수정") ;
        }
    }else{
        //$c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
        if(ds_out.getCellData(0, "dcsnYn") == "1") {
            ds_out.setCellData(0, "dcsnYn", "0");
        }else {
            ds_out.setCellData(0, "dcsnYn", "1");
        }
        return;
    }
};

// 서브미션
scwin.sbm_tr_ctrtclose_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    scwin.uppermostBizDomCd = scwin.hid_uppermostBizDomCd;
    if(ds_out3.getCellData(0, "closeState") == "Y") {
