scwin.f_displayFm = function(e) {
    let val = e;

    let first = val.charAt(0).toUpperCase();
    if (!/[A-Z]/.test(first)) {
        // 첫 글자가 영문이 아니면 제거
        first = '';
    }
    let rest = val.substring(1).replace(/[^0-9]/g, '');
    if (rest.length > 11) {
            rest = rest.substring(0, 11) + '-' + rest.substring(11, 15);
        }
    let formatted = (first + rest).substring(0, 16);

    return formatted;
};

